using System;
using System.Threading.Tasks;
using Azure.Core;
using Azure.Identity;
using Azure.ResourceManager;
using Azure.ResourceManager.ContainerServiceFleet;
using Azure.ResourceManager.ContainerServiceFleet.Models;
using Azure.ResourceManager.Resources;
using NUnit.Framework;

namespace Azure.ResourceManager.ContainerServiceFleet.Tests.Samples
{
    public class Sample1_FleetBasicOperations : SamplesBase<ContainerServiceFleetManagementTestEnvironment>
    {
        [Test]
        [AsyncOnly]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateFleet()
        {
            #region Snippet:CreateFleet
            string subscriptionId = "<subscriptionId>";
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = client.GetSubscriptionResource(
                SubscriptionResource.CreateResourceIdentifier(subscriptionId));

            ResourceGroupResource resourceGroup = (await subscription.GetResourceGroupAsync("<resourceGroupName>")).Value;

            ContainerServiceFleetCollection fleets = resourceGroup.GetContainerServiceFleets();

            ContainerServiceFleetData fleetData = new ContainerServiceFleetData(AzureLocation.EastUS);
            ArmOperation<ContainerServiceFleetResource> operation = await fleets.CreateOrUpdateAsync(
                WaitUntil.Completed,
                "<fleetName>",
                fleetData);

            ContainerServiceFleetResource fleet = operation.Value;
            Console.WriteLine($"Created fleet: {fleet.Data.Name}");
            #endregion
        }

        [Test]
        [AsyncOnly]
        [Ignore("Only verifying that the sample builds")]
        public async Task AddFleetMember()
        {
            #region Snippet:AddFleetMember
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            ResourceIdentifier fleetId = ContainerServiceFleetResource.CreateResourceIdentifier(
                "<subscriptionId>", "<resourceGroupName>", "<fleetName>");

            ContainerServiceFleetResource fleet = client.GetContainerServiceFleetResource(fleetId);

            ContainerServiceFleetMemberCollection members = fleet.GetContainerServiceFleetMembers();

            ContainerServiceFleetMemberData memberData = new ContainerServiceFleetMemberData
            {
                ClusterResourceId = new ResourceIdentifier(
                    "/subscriptions/<subscriptionId>/resourceGroups/<rg>/providers/Microsoft.ContainerService/managedClusters/<aksName>"),
                Group = "staging"
            };

            ArmOperation<ContainerServiceFleetMemberResource> operation = await members.CreateOrUpdateAsync(
                WaitUntil.Completed,
                "<memberName>",
                memberData);

            ContainerServiceFleetMemberResource member = operation.Value;
            Console.WriteLine($"Added member: {member.Data.Name}");
            #endregion
        }

        [Test]
        [AsyncOnly]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateUpdateRun()
        {
            #region Snippet:CreateUpdateRun
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            ResourceIdentifier fleetId = ContainerServiceFleetResource.CreateResourceIdentifier(
                "<subscriptionId>", "<resourceGroupName>", "<fleetName>");

            ContainerServiceFleetResource fleet = client.GetContainerServiceFleetResource(fleetId);

            ContainerServiceUpdateRunData runData = new ContainerServiceUpdateRunData
            {
                UpdateStrategySnapshot = new ContainerServiceFleetUpdateStrategySnapshot
                {
                    Stages =
                    {
                        new ContainerServiceFleetUpdateStage("stage1")
                        {
                            Groups = { new ContainerServiceFleetUpdateGroup("staging") }
                        }
                    }
                },
                ManagedClusterUpdate = new ContainerServiceFleetManagedClusterUpdate(
                    new ContainerServiceFleetManagedClusterUpgradeSpec(
                        ContainerServiceFleetManagedClusterUpgradeType.Full)
                    {
                        KubernetesVersion = "1.30"
                    })
            };

            ArmOperation<ContainerServiceUpdateRunResource> operation = await fleet
                .GetContainerServiceUpdateRuns()
                .CreateOrUpdateAsync(WaitUntil.Completed, "<updateRunName>", runData);

            ContainerServiceUpdateRunResource updateRun = operation.Value;
            Console.WriteLine($"Created update run: {updateRun.Data.Name}");
            #endregion
        }

        [Test]
        [AsyncOnly]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateAutoUpgradeProfile()
        {
            #region Snippet:CreateAutoUpgradeProfile
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            ResourceIdentifier fleetId = ContainerServiceFleetResource.CreateResourceIdentifier(
                "<subscriptionId>", "<resourceGroupName>", "<fleetName>");

            ContainerServiceFleetResource fleet = client.GetContainerServiceFleetResource(fleetId);

            AutoUpgradeProfileData profileData = new AutoUpgradeProfileData
            {
                Channel = AutoUpgradeChannel.Regular
            };

            ArmOperation<AutoUpgradeProfileResource> operation = await fleet
                .GetAutoUpgradeProfiles()
                .CreateOrUpdateAsync(WaitUntil.Completed, "<profileName>", profileData);

            AutoUpgradeProfileResource profile = operation.Value;
            Console.WriteLine($"Created AutoUpgrade profile: {profile.Data.Name}");
            #endregion
        }
    }
}
```

